**Key Security Controls**:
- **Environment Variables**: API keys loaded from environment, not hardcoded in source
- **Configuration Validation**: Application fails fast if required secrets are missing
- **Safe Logging**: Error messages never include sensitive credentials
- **Context Support**: Enables proper timeout and cancellation handling

For production deployments, you need a secrets management solution that supports automatic rotation, audit logging, and fine-grained access control. HashiCorp Vault is the industry standard for this purpose.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/tls"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"sync"
	"time"

	vault "github.com/hashicorp/vault/api"
)

// SecretsManager handles secure secrets retrieval with caching and rotation
type SecretsManager struct {
	client      *vault.Client
	cache       map[string]*CachedSecret
	cacheMu     sync.RWMutex
	auditLogger *log.Logger
}

// CachedSecret holds a secret with expiration metadata
type CachedSecret struct {
	Value     string
	ExpiresAt time.Time
	Version   int
}

// NewSecretsManager initializes a secure connection to Vault
func NewSecretsManager(ctx context.Context) (*SecretsManager, error) {
	config := vault.DefaultConfig()

	// Production: Use Vault address from environment
	config.Address = os.Getenv("VAULT_ADDR")
	if config.Address == "" {
		return nil, fmt.Errorf("VAULT_ADDR environment variable required")
	}

	// Production TLS configuration
	config.HttpClient = &http.Client{
		Timeout: 30 * time.Second,
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{
				MinVersion: tls.VersionTLS13,
			},
		},
	}

	client, err := vault.NewClient(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create vault client: %w", err)
	}

	// Authenticate using Kubernetes service account (recommended for K8s)
	// or AppRole for non-K8s environments
	token := os.Getenv("VAULT_TOKEN")
	if token == "" {
		// Use Kubernetes auth in production
		if err := authenticateK8s(ctx, client); err != nil {
			return nil, fmt.Errorf("vault authentication failed: %w", err)
		}
	} else {
		client.SetToken(token)
	}

	// Setup audit logging
	auditLogger := log.New(os.Stdout, "[SECRETS-AUDIT] ", log.LstdFlags|log.LUTC)

	return &SecretsManager{
		client:      client,
		cache:       make(map[string]*CachedSecret),
		auditLogger: auditLogger,
	}, nil
}

// authenticateK8s performs Kubernetes-based authentication
func authenticateK8s(ctx context.Context, client *vault.Client) error {
	// Read Kubernetes service account token
	jwt, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		return fmt.Errorf("failed to read service account token: %w", err)
	}

	role := os.Getenv("VAULT_ROLE")
	if role == "" {
		return fmt.Errorf("VAULT_ROLE environment variable required")
	}

	data := map[string]interface{}{
		"jwt":  string(jwt),
		"role": role,
	}

	secret, err := client.Logical().WriteWithContext(ctx, "auth/kubernetes/login", data)
	if err != nil {
		return fmt.Errorf("kubernetes auth failed: %w", err)
	}

	client.SetToken(secret.Auth.ClientToken)
	return nil
}

// GetSecret retrieves a secret with caching and audit logging
func (sm *SecretsManager) GetSecret(ctx context.Context, path, key string) (string, error) {
	cacheKey := path + ":" + key

	// Check cache first
	sm.cacheMu.RLock()
	if cached, ok := sm.cache[cacheKey]; ok {
		if time.Now().Before(cached.ExpiresAt) {
			sm.cacheMu.RUnlock()
			return cached.Value, nil
		}
	}
	sm.cacheMu.RUnlock()

	// Fetch from Vault
	secret, err := sm.client.Logical().ReadWithContext(ctx, path)
	if err != nil {
		sm.auditLogger.Printf("FAILED secret retrieval: path=%s, error=%v", path, err)
		return "", fmt.Errorf("failed to read secret from vault: %w", err)
	}

	if secret == nil || secret.Data == nil {
		return "", fmt.Errorf("secret not found at path: %s", path)
	}

	// Handle KV v2 data structure
	data, ok := secret.Data["data"].(map[string]interface{})
	if !ok {
		data = secret.Data
	}

	value, ok := data[key].(string)
	if !ok {
		return "", fmt.Errorf("key %s not found in secret", key)
	}

	// Cache the secret with TTL
	sm.cacheMu.Lock()
	sm.cache[cacheKey] = &CachedSecret{
		Value:     value,
		ExpiresAt: time.Now().Add(5 * time.Minute),
		Version:   1,
	}
	sm.cacheMu.Unlock()

	// Audit log (never log the actual secret value)
	sm.auditLogger.Printf("SUCCESS secret retrieval: path=%s, key=%s", path, key)

	return value, nil
}

// RotateSecret forces a cache refresh for rotation scenarios
func (sm *SecretsManager) RotateSecret(ctx context.Context, path, key string) error {
	cacheKey := path + ":" + key

	sm.cacheMu.Lock()
	delete(sm.cache, cacheKey)
	sm.cacheMu.Unlock()

	// Force re-fetch
	_, err := sm.GetSecret(ctx, path, key)
	if err != nil {
		sm.auditLogger.Printf("ROTATION FAILED: path=%s, key=%s, error=%v", path, key, err)
		return err
	}

	sm.auditLogger.Printf("ROTATION SUCCESS: path=%s, key=%s", path, key)
	return nil
}

// AppConfig holds application secrets
type AppConfig struct {
	StripeAPIKey string
	DatabaseDSN  string
	JWTSecret    string
}

// LoadAppConfig loads all application secrets from Vault
func LoadAppConfig(ctx context.Context, sm *SecretsManager, env string) (*AppConfig, error) {
	basePath := fmt.Sprintf("secret/data/%s/myapp", env)

	stripeKey, err := sm.GetSecret(ctx, basePath+"/stripe", "api_key")
	if err != nil {
		return nil, fmt.Errorf("failed to load stripe key: %w", err)
	}

	dbDSN, err := sm.GetSecret(ctx, basePath+"/database", "dsn")
	if err != nil {
		return nil, fmt.Errorf("failed to load database dsn: %w", err)
	}

	jwtSecret, err := sm.GetSecret(ctx, basePath+"/auth", "jwt_secret")
	if err != nil {
		return nil, fmt.Errorf("failed to load jwt secret: %w", err)
	}

	return &AppConfig{
		StripeAPIKey: stripeKey,
		DatabaseDSN:  dbDSN,
		JWTSecret:    jwtSecret,
	}, nil
}

// HealthCheck endpoint handler that checks Vault connectivity
func (sm *SecretsManager) HealthCheck(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	health, err := sm.client.Sys().HealthWithContext(ctx)
	if err != nil {
		w.WriteHeader(http.StatusServiceUnavailable)
		json.NewEncoder(w).Encode(map[string]string{
			"status": "unhealthy",
			"error":  "vault connection failed",
		})
		return
	}

	if !health.Initialized || health.Sealed {
		w.WriteHeader(http.StatusServiceUnavailable)
		json.NewEncoder(w).Encode(map[string]string{
			"status": "unhealthy",
			"error":  "vault not ready",
		})
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "healthy"})
}

func main() {
	ctx := context.Background()

	// Initialize secrets manager
	sm, err := NewSecretsManager(ctx)
	if err != nil {
		log.Fatalf("Failed to initialize secrets manager: %v", err)
	}

	// Load environment from ENVIRONMENT variable
	env := os.Getenv("ENVIRONMENT")
	if env == "" {
		env = "development"
	}

	// Load application configuration
	config, err := LoadAppConfig(ctx, sm, env)
	if err != nil {
		log.Fatalf("Failed to load application config: %v", err)
	}

	log.Printf("Application started in %s environment", env)
	_ = config // Use config for application logic
}
```

