  verifyJWT, // Must be logged in with password/MFA first
  rateLimiter({ windowMs: 3600000, max: 3 }), // 3 enrollments per hour
  async (req, res) => {
    const { publicKey, biometryType, deviceId, deviceModel, osVersion, platform, attestation } = req.body;
    const userId = req.user.id;

    try {
      // Validate public key format
      if (!isValidPublicKey(publicKey)) {
