        }
      }

      // Check for existing biometric keys and handle migration
      const existingKeys = await BiometricKey.find({ userId, isActive: true });
      if (existingKeys.length >= 3) {
        return res.status(400).json({ 
          code: 'MAX_DEVICES_REACHED',
          message: 'Maximum 3 biometric devices allowed'
