// Generate challenge for authentication
router.post('/biometric/challenge',
  rateLimiter({ windowMs: 60000, max: 10 }), // 10 challenges per minute
  async (req, res) => {
    const { deviceId, timestamp } = req.body;

    try {
      // Check if device has enrolled biometric key
      const biometricKey = await BiometricKey.findOne({
        deviceId,
        isActive: true
      });

      if (!biometricKey) {
        // Don't reveal if device is enrolled or not
        return res.status(401).json({ code: 'AUTH_REQUIRED' });
      }

      // Check for account lockout
      if (biometricKey.failedAttempts >= 5) {
        const lockoutEnd = new Date(biometricKey.lastFailedAt.getTime() + 30 * 60000);
        if (new Date() < lockoutEnd) {
          return res.status(429).json({
            code: 'ACCOUNT_LOCKED',
            retryAfter: Math.ceil((lockoutEnd - new Date()) / 1000)
          });
        }
        // Reset after lockout period
        biometricKey.failedAttempts = 0;
        await biometricKey.save();
      }

      // Generate cryptographically secure challenge
      const challenge = crypto.randomBytes(32).toString('base64');
      const challengeId = crypto.randomUUID();
      const expiresAt = new Date(Date.now() + CHALLENGE_TTL_MS);

      // Store challenge with metadata
      challengeStore.set(challengeId, {
        challenge,
        deviceId,
        keyId: biometricKey.keyId,
        userId: biometricKey.userId,
        expiresAt,
        used: false
      });

      // Cleanup expired challenges
      setTimeout(() => challengeStore.delete(challengeId), CHALLENGE_TTL_MS);

      res.json({
        challenge,
        challengeId,
        expiresAt: expiresAt.toISOString()
      });

    } catch (error) {
      console.error('Challenge generation error:', error);
      res.status(500).json({ code: 'SERVER_ERROR' });
    }
  }
);

// Verify biometric signature
router.post('/biometric/verify',
  rateLimiter({ windowMs: 60000, max: 5 }), // 5 attempts per minute
  async (req, res) => {
    const { challengeId, signature, deviceId, platform, appVersion } = req.body;

    try {
      // Retrieve and validate challenge
      const challengeData = challengeStore.get(challengeId);

      if (!challengeData) {
        await AuditLog.create({
          event: 'INVALID_CHALLENGE_ID',
          severity: 'MEDIUM',
          details: { deviceId, ip: req.ip }
        });
        return res.status(401).json({ code: 'INVALID_CHALLENGE' });
      }

      // Check challenge expiry
      if (new Date() > challengeData.expiresAt) {
        challengeStore.delete(challengeId);
        return res.status(401).json({ code: 'CHALLENGE_EXPIRED' });
      }

      // Prevent challenge reuse
      if (challengeData.used) {
        await alertService.sendSecurityAlert({
          type: 'CHALLENGE_REUSE_ATTEMPT',
          deviceId,
          severity: 'HIGH'
        });
        return res.status(401).json({ code: 'CHALLENGE_ALREADY_USED' });
      }

      // Verify device binding
      if (challengeData.deviceId !== deviceId) {
        await AuditLog.create({
          event: 'DEVICE_MISMATCH',
          severity: 'HIGH',
          details: { expected: challengeData.deviceId, received: deviceId }
        });
        return res.status(401).json({ code: 'DEVICE_MISMATCH' });
      }

      // Get stored public key
      const biometricKey = await BiometricKey.findOne({
        keyId: challengeData.keyId,
        isActive: true
      });

      if (!biometricKey) {
        return res.status(401).json({ code: 'KEY_NOT_FOUND' });
      }

      // CRITICAL: Check if biometric set has changed (new fingerprint added)
      const currentBiometricHash = await getBiometricSetHash(deviceId);
      if (currentBiometricHash !== biometricKey.biometricSetHash) {
        // Biometric enrollment changed - require re-authentication
        biometricKey.isActive = false;
        await biometricKey.save();

        await AuditLog.create({
          userId: biometricKey.userId,
          event: 'BIOMETRIC_SET_CHANGED',
          severity: 'HIGH',
          details: { deviceId, keyId: biometricKey.keyId }
        });

        await alertService.notifyUser(biometricKey.userId, {
          title: 'Biometric Change Detected',
          message: 'A new fingerprint was detected. Please re-enroll biometrics.'
        });

        return res.status(401).json({
          code: 'BIOMETRIC_CHANGED',
          message: 'Biometric set has changed. Re-enrollment required.'
        });
      }

      // Verify cryptographic signature
      const isValid = verifySignature(
        challengeData.challenge,
        signature,
        biometricKey.publicKey
      );

      // Mark challenge as used regardless of result
      challengeData.used = true;

      if (!isValid) {
        biometricKey.failedAttempts += 1;
        biometricKey.lastFailedAt = new Date();
        await biometricKey.save();

        await AuditLog.create({
          userId: biometricKey.userId,
          event: 'BIOMETRIC_VERIFY_FAILED',
          severity: 'MEDIUM',
          details: { deviceId, attempts: biometricKey.failedAttempts }
        });

        if (biometricKey.failedAttempts >= 5) {
          await alertService.sendSecurityAlert({
            userId: biometricKey.userId,
            type: 'BIOMETRIC_LOCKOUT',
            severity: 'HIGH'
          });
        }

        return res.status(401).json({ code: 'SIGNATURE_INVALID' });
      }

      // Success! Reset failed attempts and update last used
      biometricKey.failedAttempts = 0;
      biometricKey.lastUsedAt = new Date();
      await biometricKey.save();

      // Generate session token
      const sessionToken = await generateSecureSessionToken(biometricKey.userId, {
        deviceId,
        authMethod: 'biometric',
        keyId: biometricKey.keyId
      });

      await AuditLog.create({
        userId: biometricKey.userId,
        event: 'BIOMETRIC_LOGIN_SUCCESS',
        severity: 'INFO',
        details: { deviceId, ip: req.ip }
      });

      res.json({
        sessionToken,
        expiresIn: 3600,
        userId: biometricKey.userId
      });

    } catch (error) {
      console.error('Verification error:', error);
      res.status(500).json({ code: 'VERIFICATION_ERROR' });
    }
  }
);

function isValidPublicKey(publicKey) {
  try {
    crypto.createPublicKey({
      key: Buffer.from(publicKey, 'base64'),
      format: 'der',
      type: 'spki'
    });
    return true;
  } catch {
    return false;
  }
}

module.exports = router;
