**Key Security Controls**:
- **Environment variables**: Keys loaded at runtime from environment, not compiled into bytecode
- **Fail-fast validation**: Application refuses to start if required secrets are missing
- **No logging of secrets**: Only business context is logged, never credential values
- **Easy rotation**: Keys can be rotated by updating environment without code changes

You're right to be cautious. Environment variables can be exposed through process listings, crash dumps, container orchestration logs, and debugging tools. For production systems, you should use a dedicated secrets management system like HashiCorp Vault, AWS Secrets Manager, or Azure Key Vault. These provide encryption at rest, access auditing, automatic rotation, and fine-grained access controls.

**PRODUCTION PATTERN**:

```java
import software.amazon.awssdk.services.secretsmanager.SecretsManagerClient;
import software.amazon.awssdk.services.secretsmanager.model.GetSecretValueRequest;
import software.amazon.awssdk.services.secretsmanager.model.GetSecretValueResponse;
import software.amazon.awssdk.regions.Region;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;
import java.time.Instant;

public class SecureSecretsManager {
    private static final Logger logger = Logger.getLogger(SecureSecretsManager.class.getName());
    private static final ObjectMapper objectMapper = new ObjectMapper();

    private final SecretsManagerClient secretsClient;
    private final ConcurrentHashMap<String, CachedSecret> secretCache;
    private final ScheduledExecutorService refreshScheduler;
    private final long cacheTtlSeconds;

    // Cached secret with expiration tracking
    private static class CachedSecret {
        final String value;
        final Instant expiresAt;

        CachedSecret(String value, long ttlSeconds) {
            this.value = value;
            this.expiresAt = Instant.now().plusSeconds(ttlSeconds);
        }

        boolean isExpired() {
            return Instant.now().isAfter(expiresAt);
        }
    }

    public SecureSecretsManager(String region, long cacheTtlSeconds) {
        this.secretsClient = SecretsManagerClient.builder()
            .region(Region.of(region))
            .build();
        this.secretCache = new ConcurrentHashMap<>();
        this.cacheTtlSeconds = cacheTtlSeconds;
        this.refreshScheduler = Executors.newSingleThreadScheduledExecutor();

        // Schedule periodic cache cleanup
        refreshScheduler.scheduleAtFixedRate(
            this::cleanExpiredCache, 
            cacheTtlSeconds, 
            cacheTtlSeconds / 2, 
            TimeUnit.SECONDS
        );
    }

    public String getSecret(String secretName) {
        // Check cache first
        CachedSecret cached = secretCache.get(secretName);
        if (cached != null && !cached.isExpired()) {
            logger.fine("Secret cache hit: " + secretName);
            return cached.value;
        }

        // Fetch from Secrets Manager with audit logging
        try {
            logger.info(String.format("Fetching secret from Secrets Manager: %s", secretName));

            GetSecretValueRequest request = GetSecretValueRequest.builder()
                .secretId(secretName)
                .build();

            GetSecretValueResponse response = secretsClient.getSecretValue(request);
            String secretValue = response.secretString();

            // Cache the secret
            secretCache.put(secretName, new CachedSecret(secretValue, cacheTtlSeconds));

            // Audit log the access (not the value!)
            logSecretAccess(secretName, "RETRIEVED");

            return secretValue;
        } catch (Exception e) {
            logger.severe(String.format("Failed to retrieve secret %s: %s", 
                secretName, e.getClass().getSimpleName()));
            logSecretAccess(secretName, "ACCESS_FAILED");
            throw new SecretAccessException("Unable to retrieve secret: " + secretName, e);
        }
    }

    public Map<String, String> getSecretAsMap(String secretName) {
        String secretJson = getSecret(secretName);
        try {
            return objectMapper.readValue(secretJson, Map.class);
        } catch (Exception e) {
            throw new SecretAccessException("Failed to parse secret as JSON: " + secretName, e);
        }
    }

    private void cleanExpiredCache() {
        secretCache.entrySet().removeIf(entry -> entry.getValue().isExpired());
    }

    private void logSecretAccess(String secretName, String action) {
        // Send to SIEM for security monitoring
        logger.info(String.format(
            "SECRET_ACCESS|name=%s|action=%s|timestamp=%s|service=%s",
            secretName, action, Instant.now(), getServiceIdentifier()
        ));
    }

    private String getServiceIdentifier() {
        return System.getenv().getOrDefault("SERVICE_NAME", "unknown-service");
    }

    public void shutdown() {
        refreshScheduler.shutdown();
        secretsClient.close();
        // Clear secrets from memory
        secretCache.clear();
    }
}

// Custom exception for secret access failures
class SecretAccessException extends RuntimeException {
    public SecretAccessException(String message, Throwable cause) {
        super(message, cause);
    }
}
```

