- Environment variables keep secrets out of source code and version control
- Required variable validation ensures application fails fast if misconfigured
- Masked logging prevents credential exposure in logs
- Custom exceptions avoid leaking implementation details to attackers

For production environments, you need proper secrets management infrastructure. Enterprise solutions use dedicated secret stores, automatic rotation, and strict access controls.

**PRODUCTION PATTERN**:

```php
<?php
// Production-grade secrets management with multiple backends
declare(strict_types=1);

namespace App\Security;

use Aws\SecretsManager\SecretsManagerClient;
use Aws\Exception\AwsException;
use HashiCorp\Vault\Client as VaultClient;
use Psr\Log\LoggerInterface;
use Psr\Cache\CacheItemPoolInterface;

interface SecretsProviderInterface {
    public function getSecret(string $key): ?string;
    public function isHealthy(): bool;
}

class AWSSecretsManagerProvider implements SecretsProviderInterface {
    private SecretsManagerClient $client;
    private CacheItemPoolInterface $cache;
    private LoggerInterface $logger;
    private string $secretPrefix;
    private int $cacheTtl;

    public function __construct(
        CacheItemPoolInterface $cache,
        LoggerInterface $logger,
        string $region = 'us-east-1',
        string $secretPrefix = 'prod',
        int $cacheTtl = 300
    ) {
        // AWS SDK uses IAM roles in production - no hardcoded credentials
        $this->client = new SecretsManagerClient([
            'region' => $region,
            'version' => 'latest'
        ]);
        $this->cache = $cache;
        $this->logger = $logger;
        $this->secretPrefix = $secretPrefix;
        $this->cacheTtl = $cacheTtl;
    }

    public function getSecret(string $key): ?string {
        $cacheKey = "secret_{$this->secretPrefix}_{$key}";
        $cacheItem = $this->cache->getItem($cacheKey);

        if ($cacheItem->isHit()) {
            return $cacheItem->get();
        }

        try {
            $result = $this->client->getSecretValue([
                'SecretId' => "{$this->secretPrefix}/{$key}"
            ]);

            $secretValue = $result['SecretString'] ?? null;

            if ($secretValue !== null) {
                // Cache secret to reduce API calls
                $cacheItem->set($secretValue);
                $cacheItem->expiresAfter($this->cacheTtl);
                $this->cache->save($cacheItem);

                $this->logger->info('Secret retrieved from AWS Secrets Manager', [
                    'key' => $key,
                    'cache_ttl' => $this->cacheTtl
                ]);
            }

            return $secretValue;

        } catch (AwsException $e) {
            $this->logger->error('Failed to retrieve secret from AWS', [
                'key' => $key,
                'error_code' => $e->getAwsErrorCode(),
                'request_id' => $e->getAwsRequestId()
            ]);
            return null;
        }
    }

    public function isHealthy(): bool {
        try {
            $this->client->listSecrets(['MaxResults' => 1]);
            return true;
        } catch (AwsException $e) {
            return false;
        }
    }
}

class HashiCorpVaultProvider implements SecretsProviderInterface {
    private VaultClient $client;
    private LoggerInterface $logger;
    private string $mountPath;

    public function __construct(
        LoggerInterface $logger,
        string $vaultAddr,
        string $mountPath = 'secret'
    ) {
        // Token loaded from environment or Kubernetes service account
        $token = getenv('VAULT_TOKEN') ?: $this->getKubernetesToken();

        $this->client = new VaultClient([
            'base_uri' => $vaultAddr,
            'token' => $token
        ]);
        $this->logger = $logger;
        $this->mountPath = $mountPath;
    }

    private function getKubernetesToken(): string {
        $tokenPath = '/var/run/secrets/kubernetes.io/serviceaccount/token';
        if (file_exists($tokenPath)) {
            return file_get_contents($tokenPath);
        }
        throw new \RuntimeException('No Vault token available');
    }

    public function getSecret(string $key): ?string {
        try {
            $response = $this->client->read("{$this->mountPath}/data/{$key}");
            return $response['data']['data']['value'] ?? null;
        } catch (\Exception $e) {
            $this->logger->error('Failed to retrieve secret from Vault', [
                'key' => $key,
                'error' => $e->getMessage()
            ]);
            return null;
        }
    }

    public function isHealthy(): bool {
        try {
            $this->client->health();
            return true;
        } catch (\Exception $e) {
            return false;
        }
    }
}

class SecureSecretsManager {
    private array $providers;
    private LoggerInterface $logger;
    private array $secretCache = [];

    public function __construct(array $providers, LoggerInterface $logger) {
        $this->providers = $providers;
        $this->logger = $logger;
    }

    public function getSecret(string $key, bool $required = true): ?string {
        // Check in-memory cache first
        if (isset($this->secretCache[$key])) {
            return $this->secretCache[$key];
        }

        // Try each provider in order (failover pattern)
        foreach ($this->providers as $providerName => $provider) {
            if (!$provider->isHealthy()) {
                $this->logger->warning('Secrets provider unhealthy', [
                    'provider' => $providerName
                ]);
                continue;
            }

            $secret = $provider->getSecret($key);
            if ($secret !== null) {
                // Store in memory for this request only
                $this->secretCache[$key] = $secret;

                $this->logger->info('Secret loaded', [
                    'key' => $key,
                    'provider' => $providerName
                ]);

                return $secret;
            }
        }

        // Secret not found in any provider
        if ($required) {
            $this->logger->critical('Required secret not found', [
                'key' => $key
            ]);
            throw new SecretNotFoundException("Required secret '{$key}' not found");
        }

        return null;
    }

    // Secure memory cleanup
    public function clearCache(): void {
        // Overwrite memory before clearing
        foreach ($this->secretCache as $key => $value) {
            $this->secretCache[$key] = str_repeat('0', strlen($value));
        }
        $this->secretCache = [];
    }

    public function __destruct() {
        $this->clearCache();
    }
}

class SecretNotFoundException extends \RuntimeException {}

// Usage in production service
class ProductionPaymentService {
    private SecureSecretsManager $secrets;
    private LoggerInterface $logger;
    private string $environment;

    public function __construct(
        SecureSecretsManager $secrets,
        LoggerInterface $logger
    ) {
        $this->secrets = $secrets;
        $this->logger = $logger;
        $this->environment = getenv('APP_ENV') ?: 'production';
    }

    public function processPayment(string $customerId, int $amount): array {
        // Get API key from secure secrets manager
        $apiKey = $this->secrets->getSecret('stripe/api_key');

        \Stripe\Stripe::setApiKey($apiKey);

        $requestId = bin2hex(random_bytes(16));

        try {
            $charge = \Stripe\Charge::create([
                'customer' => $customerId,
                'amount' => $amount,
                'currency' => 'usd',
                'metadata' => ['request_id' => $requestId]
            ]);

            $this->logger->info('Payment processed', [
                'request_id' => $requestId,
                'charge_id' => $charge->id,
                'amount' => $amount,
                'customer_masked' => $this->maskSensitiveId($customerId)
            ]);

            return [
                'success' => true,
                'charge_id' => $charge->id,
                'request_id' => $requestId
            ];

        } catch (\Stripe\Exception\ApiErrorException $e) {
            $this->logger->error('Payment failed', [
                'request_id' => $requestId,
                'error_type' => get_class($e),
                'customer_masked' => $this->maskSensitiveId($customerId)
            ]);

            throw new PaymentProcessingException(
                'Payment processing failed',
                $requestId,
                $e
            );
        } finally {
            // Clear sensitive data from memory
            $apiKey = str_repeat('0', strlen($apiKey));
            unset($apiKey);
        }
    }

    private function maskSensitiveId(string $id): string {
        $length = strlen($id);
        if ($length <= 4) {
            return str_repeat('*', $length);
        }
        return str_repeat('*', $length - 4) . substr($id, -4);
    }
}

class PaymentProcessingException extends \RuntimeException {
    private string $requestId;

    public function __construct(string $message, string $requestId, \Throwable $previous = null) {
        parent::__construct($message, 0, $previous);
        $this->requestId = $requestId;
    }

    public function getRequestId(): string {
        return $this->requestId;
    }
}
```

**Kubernetes Deployment Configuration**:
```yaml
# kubernetes/deployment.yaml
apiVersion: apps/v1
kind: Deployment
metadata:
  name: payment-service
spec:
  template:
    spec:
      serviceAccountName: payment-service-sa
      containers:
      - name: app
        image: payment-service:latest
        env:
        # Reference secrets from Kubernetes Secrets
        - name: STRIPE_API_KEY
          valueFrom:
            secretKeyRef:
              name: payment-secrets
              key: stripe-api-key
        # Or use External Secrets Operator for AWS/Vault
        - name: AWS_REGION
          value: "us-east-1"
        - name: VAULT_ADDR
          value: "https://vault.internal:8200"
        volumeMounts:
        - name: secrets-store
          mountPath: "/mnt/secrets"
          readOnly: true
      volumes:
      - name: secrets-store
        csi:
          driver: secrets-store.csi.k8s.io
          readOnly: true
          volumeAttributes:
            secretProviderClass: aws-secrets
```

**Defense in Depth Layers**:

1. **Secret Storage Layer**: Never in code, always in dedicated secret stores
```php
<?php
// IAM roles provide access - no credentials in application
$secretsManager = new SecretsManagerClient([
    'region' => 'us-east-1',
    'version' => 'latest'
    // Credentials resolved from IAM role automatically
]);
```

2. **Access Control Layer**: Least privilege and audit logging
```php
<?php
// Each service gets only the secrets it needs
// Defined via IAM policies or Vault policies
$allowedSecrets = [
    'payment-service' => ['stripe/*', 'database/payment-db'],
    'auth-service' => ['oauth/*', 'database/auth-db']
];
```

3. **Automatic Rotation Layer**: Secrets rotated without application changes
```php
<?php
// Application doesn't care about rotation - always gets current secret
class RotationAwareSecretProvider {
    public function getSecret(string $key): string {
        // Cache invalidated when secret rotates (via event notification)
        $secret = $this->cache->get($key) ?? $this->fetchAndCache($key);
        return $secret;
    }
}
```

**Additional Protections**:

- **Pre-commit hooks** to scan for accidental secret commits:
```bash
# .pre-commit-config.yaml
repos:
  - repo: https://github.com/Yelp/detect-secrets
    rev: v1.4.0
    hooks:
      - id: detect-secrets
        args: ['--baseline', '.secrets.baseline']
```

- **Runtime secret detection** to prevent logging:
```php
<?php
class SecureLogger implements LoggerInterface {
    private array $sensitivePatterns = [
        '/sk_live_[a-zA-Z0-9]{24}/',      // Stripe live keys
        '/AKIA[A-Z0-9]{16}/',              // AWS access keys
        '/ghp_[a-zA-Z0-9]{36}/',           // GitHub tokens
    ];

    public function log($level, $message, array $context = []): void {
        $sanitized = $this->sanitize($message);
        $sanitizedContext = $this->sanitizeContext($context);
        // Forward to actual logger
    }

    private function sanitize(string $message): string {
        foreach ($this->sensitivePatterns as $pattern) {
            $message = preg_replace($pattern, '[REDACTED]', $message);
        }
        return $message;
    }
}
```

- **Secret expiration monitoring** with alerts:
```php
<?php
// Monitor secret age and alert before expiration
$secretMetadata = $secretsManager->describeSecret(['SecretId' => $key]);
$lastRotated = $secretMetadata['LastRotatedDate'] ?? $secretMetadata['CreatedDate'];
$daysSinceRotation = (time() - $lastRotated->getTimestamp()) / 86400;

if ($daysSinceRotation > 80) { // Alert at 80 days for 90-day rotation
    $alerting->sendAlert('Secret approaching rotation deadline', [
        'secret' => $key,
        'days_since_rotation' => $daysSinceRotation
    ]);
}
